def gen(rng, size):
    keys = ['a', 'b', 'c', 'd', 'e', 'f']
    parts = []
    n = max(1, size // 4)
    for _ in range(n):
        if rng.random() < 0.6:
            parts.append('(' + rng.choice(keys) + ')')
        else:
            parts.append(rng.choice('xyzw'))
    s = ''.join(parts)
    known = []
    for k in keys:
        if rng.random() < 0.5:
            known.append([k, ''.join(rng.choice('LMNOP') for _ in range(rng.randrange(1, 4)))])
    return [s, known]

