class Solution:
    def evaluate(self, s, knowledge):
        d = {}
        for k, v in knowledge:
            d[k] = v
        out = []
        i = 0
        n = len(s)
        while i < n:
            if s[i] == '(':
                j = i + 1
                key = ''
                while s[j] != ')':
                    key += s[j]
                    j += 1
                out.append(d.get(key, '?'))
                i = j + 1
            else:
                out.append(s[i])
                i += 1
        return ''.join(out)

