class Solution:
    def evaluate(self, s, knowledge):
        d = {k: v for k, v in knowledge}
        res = []
        i = 0
        n = len(s)
        while i < n:
            c = s[i]
            if c == '(':
                j = s.index(')', i + 1)
                key = s[i + 1:j]
                res.append(d.get(key, '?'))
                i = j + 1
            else:
                res.append(c)
                i += 1
        return ''.join(res)

