var evaluate = function(s, knowledge) {
    const d = new Map();
    for (const [k, v] of knowledge) d.set(k, v);
    const res = [];
    const n = s.length;
    let i = 0;
    while (i < n) {
        if (s[i] === '(') {
            const j = s.indexOf(')', i + 1);
            const key = s.slice(i + 1, j);
            res.push(d.has(key) ? d.get(key) : '?');
            i = j + 1;
        } else {
            res.push(s[i]);
            i++;
        }
    }
    return res.join('');
};
